    // Write the magic prefix ("cctp-forward") - 12 bytes, rest of 24-byte section is zero-padded
    const encoder = new TextEncoder();
    const magicBytes = encoder.encode(CCTP_FORWARD_MAGIC_PREFIX);
    buffer.set(magicBytes, 0);
